.chat-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    background: #1a1d21;
    min-width: 0;
}

.chat-main.thread-open {
    max-width: 55%;
}

.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #2c2d30;
    flex-shrink: 0;
}

.main-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1.05rem;
    font-weight: 700;
}

.header-desc {
    font-size: 0.82rem;
    color: #9a9b9e;
}

/* ── Message list ── */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #9a9b9e;
    font-size: 0.85rem;
}

.message-row {
    padding: 8px 8px;
    border-radius: 6px;
    position: relative;
    transition: background 0.1s;
}

.message-row:hover {
    background: #222529;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.msg-author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #fff;
}

.msg-time {
    font-size: 0.75rem;
    color: #9a9b9e;
}

.msg-content {
    font-size: 0.93rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #2c2d30;
    border: 1px solid #3c3d41;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.82rem;
    color: #d1d2d3;
    cursor: pointer;
    transition: background 0.1s;
