.thread-link {
    background: none;
    border: none;
    color: #1d9bd1;
    font-size: 0.82rem;
    cursor: pointer;
    padding: 4px 0 0;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

